1	/**
2	 * Integration tests for migration 0001_core_tables.sql and migrate.ts.
3	 *
4	 * Covers all feat-db-schema acceptance criteria:
5	 *   AC-1  All seven tables exist; PRAGMA table_info returns exact columns.
6	 *   AC-2  FK constraints enforced (nonexistent workflow_id raises FK error).
7	 *   AC-3  ON DELETE CASCADE propagates workflow deletion to all children.
8	 *   AC-4  Partial index idx_pending_attention_open present and used by EXPLAIN.
9	 *   AC-5  Column types are exactly TEXT or INTEGER — no VARCHAR anywhere.
10	 *   AC-6  No columns beyond what sqlite-schema.sql specifies.
11	 *
12	 * Also covers review criteria:
13	 *   RC-1  Partial index WHERE acknowledged_at IS NULL.
14	 *   RC-2  items.data is TEXT (opaque blob), not split columns.
15	 *   RC-3  prepost_runs.when_phase CHECK (pre|post) enforced.
16	 *   RC-4  sessions.parent_session_id FK references sessions(id).
17	 */
18	
19	import { describe, it, expect, beforeEach, afterEach } from 'vitest';
20	import Database from 'better-sqlite3';
21	import fs from 'node:fs';
22	import path from 'node:path';
23	import os from 'node:os';
24	import { fileURLToPath } from 'node:url';
25	import { applyMigrations } from '../../src/server/storage/migrate.js';
26	
27	// ---------------------------------------------------------------------------
28	// Paths
29	// ---------------------------------------------------------------------------
30	
31	const __dirname = path.dirname(fileURLToPath(import.meta.url));
32	const migrationsDir = path.resolve(__dirname, '../..', 'src/server/storage/migrations');
33	
34	// ---------------------------------------------------------------------------
35	// Helpers
36	// ---------------------------------------------------------------------------
37	
38	interface ColumnInfo {
39	  cid: number;
40	  name: string;
41	  type: string;
42	  notnull: number;
43	  dflt_value: string | null;
44	  pk: number;
45	}
46	
47	let tmpDir: string;
48	
49	beforeEach(() => {
50	  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'yoke-schema-test-'));
51	});
52	
53	afterEach(() => {
54	  fs.rmSync(tmpDir, { recursive: true, force: true });
55	});
56	
57	function makeDb(): Database.Database {
58	  const dbPath = path.join(tmpDir, `${Math.random().toString(36).slice(2)}.db`);
59	  const db = new Database(dbPath);
60	  db.pragma('busy_timeout = 5000');
61	  db.pragma('journal_mode = WAL');
62	  db.pragma('synchronous = NORMAL');
63	  db.pragma('foreign_keys = ON');
64	  db.exec(
65	    'CREATE TABLE IF NOT EXISTS schema_migrations (version INTEGER PRIMARY KEY, applied_at TEXT NOT NULL)',
66	  );
67	  applyMigrations(db, migrationsDir);
68	  return db;
69	}
70	
71	function tableInfo(db: Database.Database, table: string): ColumnInfo[] {
72	  return db.prepare(`PRAGMA table_info(${table})`).all() as ColumnInfo[];
73	}
74	
75	function colNames(db: Database.Database, table: string): string[] {
76	  return tableInfo(db, table).map((c) => c.name);
77	}
78	
79	function colTypes(db: Database.Database, table: string): Record<string, string> {
80	  const out: Record<string, string> = {};
81	  for (const c of tableInfo(db, table)) out[c.name] = c.type;
82	  return out;
83	}
84	
85	// Minimal valid workflow row
86	function insertWorkflow(db: Database.Database, id: string): void {
87	  db.prepare(
88	    `INSERT INTO workflows (id, name, spec, pipeline, config, status, created_at, updated_at)
89	     VALUES (?, 'wf', 'spec', '[]', '{}', 'pending', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z')`,
90	  ).run(id);
91	}
92	
93	function insertItem(db: Database.Database, id: string, workflowId: string): void {
94	  db.prepare(
95	    `INSERT INTO items (id, workflow_id, stage_id, data, status, updated_at)
96	     VALUES (?, ?, 'stage-1', '{}', 'pending', '2026-01-01T00:00:00Z')`,
97	  ).run(id, workflowId);
98	}
99	
100	function insertSession(db: Database.Database, id: string, workflowId: string): void {
101	  db.prepare(
102	    `INSERT INTO sessions (id, workflow_id, stage, phase, agent_profile, started_at, status)
103	     VALUES (?, ?, 'stage-1', 'implement', 'default', '2026-01-01T00:00:00Z', 'running')`,
104	  ).run(id, workflowId);
