210	// ---------------------------------------------------------------------------
211	// AC-2 — FK constraints enforced
212	// ---------------------------------------------------------------------------
213	
214	describe('AC-2: FK constraints enforced', () => {
215	  it('inserting item with nonexistent workflow_id raises FK error', () => {
216	    const db = makeDb();
217	    expect(() =>
218	      db
219	        .prepare(
