294	// ---------------------------------------------------------------------------
295	// AC-3 — ON DELETE CASCADE propagates workflow deletion
296	// ---------------------------------------------------------------------------
297	
298	describe('AC-3: ON DELETE CASCADE from workflow', () => {
299	  it('deleting a workflow removes all child items, sessions, events, artifact_writes, pending_attention, prepost_runs', () => {
300	    const db = makeDb();
301	    insertWorkflow(db, 'wf-1');
302	    insertItem(db, 'item-1', 'wf-1');
303	    insertSession(db, 'sess-1', 'wf-1');
