305	    // event linked to workflow
306	    db.prepare(
307	      `INSERT INTO events (ts, workflow_id, event_type, level, message)
308	       VALUES ('2026-01-01T00:00:00Z', 'wf-1', 'test', 'info', 'hello')`,
309	    ).run();
310	
311	    // artifact_write linked to session
312	    db.prepare(
313	      `INSERT INTO artifact_writes (session_id, artifact_path, written_at, sha256)
314	       VALUES ('sess-1', '/x.ts', '2026-01-01T00:00:00Z', 'sha')`,
