441	// ---------------------------------------------------------------------------
442	// AC-6 — No columns beyond what sqlite-schema.sql specifies (already covered
443	//         by AC-1 exact column list assertions; this suite verifies count)
444	// ---------------------------------------------------------------------------
445	
446	describe('AC-6: no extra columns in any table', () => {
447	  it('column counts match the schema exactly', () => {
448	    const db = makeDb();
449	    const counts: Record<string, number> = {
450	      workflows: 12,
451	      items: 13,
452	      sessions: 22,
453	      events: 12,
454	      artifact_writes: 5,
455	      pending_attention: 6,
