480	// RC-3 — prepost_runs.when_phase CHECK (pre|post) enforced
481	// ---------------------------------------------------------------------------
482	
483	describe('RC-3: prepost_runs.when_phase CHECK constraint', () => {
484	  it('when_phase = pre is accepted', () => {
485	    const db = makeDb();
486	    insertWorkflow(db, 'wf-pp');
487	    expect(() =>
488	      db
489	        .prepare(
490	          `INSERT INTO prepost_runs (workflow_id, stage, phase, when_phase, command_name, argv, started_at)
491	           VALUES ('wf-pp', 's', 'p', 'pre', 'lint', '[]', '2026-01-01T00:00:00Z')`,
492	        )
